const src = $json.body ?? $json;

function generateSessionId() {
  const ts = Date.now().toString(36);
  const rnd = Math.random().toString(36).slice(2, 10);
  return `SES-${ts}-${rnd}`.toUpperCase();
}

let message =
  src.chatInput ||
  src.message ||
  src.text ||
  src.prompt ||
  src.userMessage ||
  src.input ||
  src.query ||
  src.lastMessage ||
  '';

const historyRaw =
  src.history ||
  src.chatHistory ||
  src.messages ||
  src.conversation ||
  [];

const history = Array.isArray(historyRaw) ? historyRaw : [];

if (!message && Array.isArray(src.messages) && src.messages.length > 0) {
  const lastUserMessage = [...src.messages].reverse().find(
    m => (m.role === 'user' || m.type === 'human' || m.sender === 'user') && (m.content || m.text)
  );
  message = lastUserMessage?.content || lastUserMessage?.text || '';
}

const sessionId =
  src.sessionId ||
  src.session_id ||
  src.conversationId ||
  src.chatId ||
  src.threadId ||
  generateSessionId();

const userId =
  src.userId ||
  src.user_id ||
  src.senderId ||
  src.customerId ||
  src.contactId ||
  null;

const language =
  src.language ||
  src.locale ||
  'es';

const organization =
  src.organization ||
  src.org ||
  'Innexia';

const projectId =
  src.projectId ||
  src.project_id ||
  null;

const currentProjectContext =
  src.currentProjectContext ||
  src.current_project_context ||
  null;

const action =
  src.action ||
  'sendMessage';

return [
  {
    json: {
      action,
      session_id: sessionId,
      user_id: userId,
      language,
      organization,
      project_id: projectId,
      message,
      history,
      current_project_context: currentProjectContext,
      source: 'chat_trigger',
      received_at: new Date().toISOString(),
      raw_input: src
    }
  }
];

let content = $json.text ?? $json.output ?? $json;

if (typeof content === 'string') {
  content = content.trim();

  if (content.startsWith('```')) {
    content = content
      .replace(/^```json\s*/i, '')
      .replace(/^```\s*/, '')
      .replace(/```$/, '')
      .trim();
  }

  content = JSON.parse(content);
}

if (content && typeof content === 'object' && content.__structured__output__object) {
  content = content.__structured__output__object;
}

content.intent = content.intent || "";
content.analysis_scope = content.analysis_scope || "none";
content.analysis_type = content.analysis_type || "new_business";
content.project_name = content.project_name || "";
content.user_goal = content.user_goal || "";
content.requires_followup = typeof content.requires_followup === 'boolean' ? content.requires_followup : false;
content.is_ready_for_engine = typeof content.is_ready_for_engine === 'boolean' ? content.is_ready_for_engine : false;
content.followup_question = content.followup_question || "";
content.missing_info = Array.isArray(content.missing_info) ? content.missing_info : [];
content.recommended_modules = Array.isArray(content.recommended_modules) ? content.recommended_modules : [];

content.normalized_brief = content.normalized_brief || {};
content.normalized_brief.title = content.normalized_brief.title || content.project_name || "";
content.normalized_brief.description = content.normalized_brief.description || "";
content.normalized_brief.objective = content.normalized_brief.objective || content.user_goal || "";
content.normalized_brief.problem_statement = content.normalized_brief.problem_statement || content.normalized_brief.description || "";
content.normalized_brief.constraints = Array.isArray(content.normalized_brief.constraints)
  ? content.normalized_brief.constraints
  : [];

return [{ json: content }];

const normalized = $('Normalize Chat Input').first().json;
const intent = $json;
function generateRequestId(sessionId) {
  const shortSession = (sessionId || 'NOSESSION').replace(/[^a-zA-Z0-9]/g, '').slice(0, 12);
  const ts = Date.now().toString(36);
  const rnd = Math.random().toString(36).substring(2, 8);
  return `REQ-${shortSession}-${ts}-${rnd}`.toUpperCase();
}
const moduleMap = { market_analysis:'market_intelligence', business_model_canvas:'bmc', strategy_design:'strategy', strategic_planning:'strategy', financial_projection:'finance', financial_forecast:'finance', risk_assessment:'risks', roadmap_plan:'roadmap', execution_plan:'activities', execution:'activities', market_intelligence:'market_intelligence', bmc:'bmc', strategy:'strategy', finance:'finance', risks:'risks', roadmap:'roadmap', verdict:'verdict', activities:'activities' };
const allowedModules = ['market_intelligence','bmc','strategy','finance','risks','roadmap','verdict','activities'];
let recommendedModules = Array.isArray(intent.recommended_modules) && intent.recommended_modules.length ? intent.recommended_modules.map(m => moduleMap[m] || m) : ['market_intelligence','bmc','strategy','roadmap','finance','risks','verdict','activities'];
recommendedModules = [...new Set(recommendedModules)].filter(m => allowedModules.includes(m));
if (!recommendedModules.includes('verdict')) recommendedModules.push('verdict');
if (intent.analysis_scope === 'full' && !recommendedModules.includes('activities')) recommendedModules.push('activities');
if (intent.analysis_scope === 'full' && !recommendedModules.includes('roadmap')) recommendedModules.push('roadmap');
const projectName = intent.project_name || intent.normalized_brief?.title || normalized.current_project_context?.name || 'Innexia Strategic Opportunity';
const callbackUrl = normalized.raw_input?.callback_url || normalized.raw_input?.callbackUrl || 'https://REPLACE_WITH_FASTAPI_HOST/api/v1/callbacks/strategy';
const payload = {
  request_id: generateRequestId(normalized.session_id),
  project_id: normalized.project_id || null,
  project_name: projectName,
  analysis_type: intent.analysis_type || 'new_business',
  language: normalized.language || 'es',
  organization: { name: normalized.organization || 'Innexia', industry: 'tecnologia y salud', country: 'Panama' },
  input_brief: {
    title: intent.normalized_brief?.title || projectName,
    description: intent.normalized_brief?.description || normalized.message,
    objective: intent.normalized_brief?.objective || intent.user_goal || 'Generar análisis estratégico',
    problem_statement: intent.normalized_brief?.problem_statement || normalized.message,
    constraints: intent.normalized_brief?.constraints || []
  },
  execution_options: { run_modules: recommendedModules, generate_kanban: true, generate_gantt: true, persist_outputs: true, strict_json: true },
  chat_context: {
    session_id: normalized.session_id, user_id: normalized.user_id, project_id: normalized.project_id || null,
    action: normalized.action || 'sendMessage', original_message: normalized.message, history: normalized.history || [],
    current_project_context: normalized.current_project_context || null, intent: intent.intent, analysis_scope: intent.analysis_scope,
    user_goal: intent.user_goal, requires_followup: intent.requires_followup, missing_info: intent.missing_info || []
  },
  callback_url: callbackUrl,
  meta: { workflow_version: 'v2.3-chat-trigger-async', source: normalized.source || 'chat_trigger_gateway', session_id: normalized.session_id, user_id: normalized.user_id, created_at: new Date().toISOString() }
};
return [{ json: payload }];

const asyncResult = $json.body ?? $json;
const root = $('Normalize Chat Input').first().json;
const intent = $('Parse JSON').first().json;
const enginePayload = $('Build Engine Payload').first().json;
const requestId = asyncResult.request_id || enginePayload.request_id || null;
const projectName = enginePayload.project_name || intent.project_name || 'tu iniciativa';
let assistantMessage = `Perfecto. Ya puse en cola el análisis estratégico para ${projectName}. En cuanto esté listo, el sistema podrá recuperar el resultado con el request ID ${requestId}.`;
if (intent.analysis_scope === 'roadmap_only') assistantMessage = `Perfecto. Ya puse en cola el roadmap estratégico para ${projectName}. Request ID: ${requestId}.`;
else if (intent.analysis_scope === 'strategy_only') assistantMessage = `Perfecto. Ya puse en cola la propuesta estratégica para ${projectName}. Request ID: ${requestId}.`;
else if (intent.analysis_scope === 'finance_only') assistantMessage = `Perfecto. Ya puse en cola el análisis financiero para ${projectName}. Request ID: ${requestId}.`;
return [{ json: { session_id: root.session_id, user_id: root.user_id, request_id: requestId, status: 'queued', source: root.source || 'chat_trigger', action: root.action || 'sendMessage', intent: intent.intent || null, analysis_scope: intent.analysis_scope || null, assistant_message: assistantMessage, suggested_next_actions: ['Consultar estado por request_id','Esperar callback del sistema','Recuperar resultado cuando finalice'], dashboard_payload: { request_id: requestId, project_name: projectName, queue_status: asyncResult.status || 'queued' } } }];

const data = $json;

if (!data.intent || typeof data.intent !== 'string') {
  throw new Error('intent faltante o inválido');
}

if (typeof data.is_ready_for_engine !== 'boolean') {
  throw new Error('is_ready_for_engine faltante o inválido');
}

if (typeof data.followup_question !== 'string') {
  throw new Error('followup_question faltante o inválido');
}

data.missing_info = Array.isArray(data.missing_info) ? data.missing_info : [];
data.recommended_modules = Array.isArray(data.recommended_modules) ? data.recommended_modules : [];

data.normalized_brief = data.normalized_brief || {};
data.normalized_brief.title = data.normalized_brief.title || "";
data.normalized_brief.description = data.normalized_brief.description || "";
data.normalized_brief.objective = data.normalized_brief.objective || "";
data.normalized_brief.problem_statement = data.normalized_brief.problem_statement || "";
data.normalized_brief.constraints = Array.isArray(data.normalized_brief.constraints)
  ? data.normalized_brief.constraints
  : [];

return [{ json: data }];

const root = $('Normalize Chat Input').first().json;
const intent = $json;

let assistantMessage =
  intent.followup_question ||
  "Cuéntame un poco más sobre la idea, negocio o iniciativa que quieres analizar.";

if (intent.intent === 'greeting' || intent.intent === 'small_talk') {
  assistantMessage = "¡Hola! Cuéntame qué idea, negocio o iniciativa quieres analizar y te ayudo a estructurarla.";
}

return [
  {
    json: {
      session_id: root.session_id,
      user_id: root.user_id,
      status: "waiting_for_more_context",
      source: root.source || "chat_trigger",
      action: root.action || "sendMessage",
      intent: intent.intent || null,
      analysis_scope: intent.analysis_scope || null,
      assistant_message: assistantMessage,
      suggested_next_actions: [],
      dashboard_payload: null
    }
  }
];
